from flask import Flask, session
import functools
import redis

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Connect to Redis server
redis_client = redis.StrictRedis(host='localhost', port=6379, db=0)

def cache(expiration_time):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Create a unique key for the function call
            key = f"cache:{func.__name__}:{str(args)}:{str(kwargs)}"
            # Try to get cached result from Redis
            cached_result = redis_client.get(key)
            if cached_result is not None:
                return eval(cached_result.decode('utf-8'))
            else:
                # Call the function and store the result in Redis
                result = func(*args, **kwargs)
                redis_client.setex(key, expiration_time, repr(result))
                return result
        return wrapper
    return decorator

@app.route('/set_session')
def set_session():
    session['user'] = 'John Doe'
    return 'Session set'

@app.route('/get_session')
def get_session():
    user = session.get('user', 'Guest')
